nsion/extension-that-defines-junit-test-extensions/runtime/src/main/java/org/acme/MyContextProvider.java, integration-tests/test-extension/tests/src/test/java/io/quarkus/it/extension/it/TemplateCanSeeByteCodeChangesDevModeIT.java, integration-tests/test-extension/tests/src/test/resources-filtered/projects/project-using-test-callback-from-extension/src/test/java/org/acme/QuarkusTestAccessingBeanInCallback.java, integration-tests/test-extension/tests/src/test/resources-filtered/projects/project-using-test-template-from-extension-with-bytecode-changes/src/test/java/org/acme/TemplatedQuarkusTest.java, test-framework/common/src/main/java/io/quarkus/test/common/PathTestHelper.java
